(function($){'use strict';const GHLWizard={currentStep:1,totalSteps:6,settings:{},init:function(){if(ghl_crm_setup_wizard_js_data.settings){this.settings={enable_user_sync:ghl_crm_setup_wizard_js_data.settings.enable_user_sync,user_register:ghl_crm_setup_wizard_js_data.settings.user_register,user_register_tags:ghl_crm_setup_wizard_js_data.settings.user_register_tags||[],woocommerce:ghl_crm_setup_wizard_js_data.settings.woocommerce,buddyboss:ghl_crm_setup_wizard_js_data.settings.buddyboss,learndash:ghl_crm_setup_wizard_js_data.settings.learndash,delete_contact_on_user_delete:ghl_crm_setup_wizard_js_data.settings.delete_contact_on_user_delete,enable_sync_logging:ghl_crm_setup_wizard_js_data.settings.enable_sync_logging,enable_role_tags:ghl_crm_setup_wizard_js_data.settings.enable_role_tags}}
this.initTagsSelect2();this.bindEvents();this.updateStepIndicators()},initTagsSelect2:function(){const $tagsSelect=$('#wizard_user_register_tags');const $userRegisterCheckbox=$('#wizard_user_register');const $tagsSection=$('#wizard_user_register_tags_section');if($tagsSelect.length===0){return}
$userRegisterCheckbox.on('change',function(){if($(this).is(':checked')){$tagsSection.slideDown(300);if($tagsSelect.find('option').length<=1){GHLWizard.loadTags()}}else{$tagsSection.slideUp(300)}});if($userRegisterCheckbox.is(':checked')){this.loadTags()}},loadTags:function(){const $tagsSelect=$('#wizard_user_register_tags');const savedTags=ghl_crm_setup_wizard_js_data.settings.user_register_tags||[];var tags=ghl_crm_setup_wizard_js_data.tags||[];$tagsSelect.empty();if(tags.length===0){$tagsSelect.append('<option value="">No tags found</option>')}else{tags.forEach((tag)=>{const tagValue=String(tag.name||tag.id||'');if(!tagValue){return}
const isSelected=savedTags.includes(tagValue);$tagsSelect.append($('<option></option>').attr('value',tagValue).text(tagValue).prop('selected',isSelected))})}
if(typeof $.fn.select2!=='undefined'){$tagsSelect.select2({tags:!0,tokenSeparators:[','],placeholder:'Select tags to apply on user registration',allowClear:!0,width:'100%',closeOnSelect:!1,scrollAfterSelect:!1})}},bindEvents:function(){$('.ghl-wizard-next').on('click',()=>this.nextStep());$('.ghl-wizard-prev').on('click',()=>this.prevStep());$('.ghl-wizard-finish').on('click',()=>this.finish());$('.ghl-tab-button').on('click',function(){const tab=$(this).data('tab');$('.ghl-tab-button').removeClass('active');$(this).addClass('active');$('.ghl-tab-content').removeClass('active');$('#'+tab+'-tab').addClass('active')});$(document).on('click','#ghl-wizard-change-connection',function(){const $trigger=$(this);const $content=$('#ghl-wizard-connection-options');$trigger.toggleClass('active');$content.slideToggle(300)});this.initManualConnectionForm()},initManualConnectionForm:function(){const self=this;$('#ghl-manual-connection-form').on('submit',function(e){e.preventDefault();const $form=$(this);const $submitBtn=$form.find('button[type="submit"]');const originalText=$submitBtn.html();$submitBtn.prop('disabled',!0).html('<span class="dashicons dashicons-update-alt" style="animation: rotation 1s infinite linear; margin-top: 3px;"></span> Connecting...');const apiToken=$('#api_token').val().trim();const locationId=$('#location_id').val().trim();const nonce=$form.find('[name="ghl_manual_connect_nonce"]').val();const formData=new FormData();formData.append('action','ghl_crm_manual_connect');formData.append('ghl_manual_connect_nonce',nonce);formData.append('api_token',apiToken);formData.append('location_id',locationId);$.ajax({url:ghl_crm_setup_wizard_js_data.ajaxUrl,type:'POST',data:formData,processData:!1,contentType:!1,success:function(response){if(response.success){if(typeof Swal!=='undefined'){Swal.fire({icon:'success',title:'Connected!',text:response.data.message||'Successfully connected to GoHighLevel',confirmButtonColor:'#4F46E5'}).then(()=>{window.location.reload()})}else{alert(response.data.message||'Successfully connected!');window.location.reload()}}else{self.showError(response.data?.message||'Connection failed. Please try again.');$submitBtn.prop('disabled',!1).html(originalText)}},error:function(xhr,status,error){self.showError('Connection error: '+error);$submitBtn.prop('disabled',!1).html(originalText)}})})},nextStep:function(){if(this.currentStep===2&&!this.isConnected()){this.showError('Please connect to GoHighLevel first');return}
this.collectCurrentStepData();if(this.currentStep<this.totalSteps){this.currentStep++;this.showStep(this.currentStep)}},prevStep:function(){if(this.currentStep>1){this.currentStep--;this.showStep(this.currentStep)}},showStep:function(step){$('.ghl-wizard-panel').removeClass('active');$(`.ghl-wizard-panel[data-step="${step}"]`).addClass('active');this.updateStepIndicators();window.scrollTo({top:0,behavior:'smooth'})},updateStepIndicators:function(){$('.ghl-setup-step').each((index,el)=>{const stepNum=index+1;if(stepNum<this.currentStep){$(el).addClass('completed').removeClass('active')}else if(stepNum===this.currentStep){$(el).addClass('active').removeClass('completed')}else{$(el).removeClass('active completed')}})},collectCurrentStepData:function(){switch(this.currentStep){case 3:this.settings.enable_user_sync=$('#wizard_enable_user_sync').is(':checked');this.settings.user_register=$('#wizard_user_register').is(':checked');this.settings.user_register_tags=$('#wizard_user_register_tags').val()||[];break;case 4:this.settings.woocommerce=$('#wizard_woocommerce').is(':checked');this.settings.buddyboss=$('#wizard_buddyboss').is(':checked');this.settings.learndash=$('#wizard_learndash').is(':checked');break;case 5:this.settings.delete_contact_on_user_delete=$('#wizard_delete_contact_on_user_delete').is(':checked');this.settings.enable_sync_logging=$('#wizard_enable_sync_logging').is(':checked');this.settings.enable_role_tags=$('#wizard_enable_role_tags').is(':checked');break}},isConnected:function(){return ghl_crm_setup_wizard_js_data.isConnected==='1'},finish:function(){const button=$('.ghl-wizard-finish');const originalText=button.html();button.prop('disabled',!0).html('<span class="dashicons dashicons-update spin"></span> Saving...');$.ajax({url:ghl_crm_setup_wizard_js_data.ajaxUrl,method:'POST',data:{action:'ghl_crm_save_wizard_settings',nonce:ghl_crm_setup_wizard_js_data.nonce,settings:this.settings},success:(response)=>{if(response.success){window.location.href=ghl_crm_setup_wizard_js_data.dashboardUrl}else{this.showError(response.data.message||'Failed to save settings');button.prop('disabled',!1).html(originalText)}},error:()=>{this.showError('Failed to save settings. Please try again.');button.prop('disabled',!1).html(originalText)}})},showError:function(message){if(typeof Swal!=='undefined'){Swal.fire({icon:'error',title:'Oops...',text:message,confirmButtonColor:'#4F46E5'})}else{alert(message)}}};$(document).ready(function(){GHLWizard.init()});const style=document.createElement('style');style.textContent=`
        @keyframes spin {
            from { transform: rotate(0deg); }
            to { transform: rotate(360deg); }
        }
        .spin { animation: spin 1s linear infinite; }
    `;document.head.appendChild(style)})(jQuery)